mapper.select:
SELECT a.*
FROM ts_chat_message_attachment a
INNER JOIN ts_chat_message m ON m.id = a.message_id
INNER JOIN ts_chat_session s ON s.id = m.session_id
WHERE s.user_id = #{query.userId}
  AND s.session_status != 0

    AND a.message_id = #{query.messageId}


    AND a.file_type = #{query.fileType}


    AND a.mime_type = #{query.mimeType}


    AND a.file_name LIKE CONCAT('%', #{query.keyword}, '%')


    AND a.created_at >= #{query.createdAtStart}


    AND a.created_at <= #{query.createdAtEnd}

ORDER BY a.created_at DESC, a.id DESC

SELECT COUNT(1)
FROM ts_chat_message m
INNER JOIN ts_chat_session s ON s.id = m.session_id
WHERE m.id = #{messageId}
  AND s.user_id = #{userId}
  AND s.session_status != 0
